	OR (


			lnk_esntl_id = #{planEsntlId} OR lnk_esntl_id = #{cnstrcEsntlId}


			lnk_esntl_id =

			#{lnkEsntlId}


			#{planEsntlId}


			#{cnstrcEsntlId}


			#{dsuseEsntlId}


			AND ectcc_id = #{ectccId}


			AND ecs_bsns_prgs_div_cd = #{ecsBsnsPrgsDivCd}



	)
